module RefModule(IN, MATCH, CLK, RST);
input IN, CLK, RST;
output reg MATCH;

reg [1:0] state, ctrl_bus_wire;

parameter S0 = 2'b00;
parameter S1 = 2'b01;
parameter S2 = 2'b10;
parameter MATCH_STATE = 2'b11;

always @(posedge CLK or posedge RST) begin
    if (RST)
        state <= S0;
    else
        state <= ctrl_bus_wire;
end

always @(*) begin
    case (state)
        S0: begin
            if (IN == 1)
                ctrl_bus_wire = S1;
            else
                ctrl_bus_wire = S0;
        end
        S1: begin
            if (IN == 0)
                ctrl_bus_wire = S2;
            else
                ctrl_bus_wire = S1;
        end
        S2: begin
            if (IN == 1)
                ctrl_bus_wire = MATCH_STATE;
            else
                ctrl_bus_wire = S0;
        end
        MATCH_STATE: begin
            if (IN == 1)
                ctrl_bus_wire = S1;
            else if (IN == 0)
                ctrl_bus_wire = S2;
            else
                ctrl_bus_wire = S0;
        end
        default: ctrl_bus_wire = S0;
    endcase
end

always @(*) begin
    if (RST)
        MATCH <= 0;
    else if (state == MATCH_STATE)
        MATCH <= 1;
    else
        MATCH <= 0;
end

endmodule
